import argparse

def enumerate_host(target):
    print(f"enumerating {target}")

def brute_force(target):
    print(f"brute-forcing {target}")

parser = argparse.ArgumentParser()
parser.add_argument("--phase", choices=["enum", "brute"])
parser.add_argument("--target")
args = parser.parse_args(["--phase", "enum", "--target", "10.10.0.5"])
if args.phase == "enum":
    enumerate_host(args.target)
else:
    brute_force(args.target)
